function cloverPlans(){return (((db.integrations||{}).clover||{}).recurringPlans||[])}function isActivePlan(p){return String(p.status||'').toLowerCase()==='active'}function weeklyEquivalent(amount,frequency){var f=String(frequency||'').toLowerCase();amount=Number(amount||0);if(f.indexOf('bi-weekly')>=0)return amount/2;if(f.indexOf('semi-month')>=0)return amount*24/52;if(f==='monthly')return amount*12/52;if(f.indexOf('bi-month')>=0)return amount*6/52;if(f.indexOf('quarter')>=0)return amount*4/52;if(f.indexOf('4 months')>=0)return amount*3/52;if(f.indexOf('semi-annual')>=0)return amount*2/52;if(f.indexOf('annual')>=0)return amount/52;if(f.indexOf('daily')>=0)return amount*7;return amount}function activePlanCustomers(){return cloverPlans().filter(isActivePlan).reduce(function(s,p){return s+Number(p.customers||0)},0)}function activePlanWeekly(){return cloverPlans().filter(isActivePlan).reduce(function(s,p){return s+Number(p.possibleWeekly!=null?p.possibleWeekly:(weeklyEquivalent(p.subtotal||p.amount,p.frequency)*Number(p.customers||0)))},0)}function isActiveRecurring(p){return String(p.status||'').toLowerCase()==='active'}function activeRecurring(){return db.recurringPayments.filter(isActiveRecurring)}function attentionRecurring(){return db.recurringPayments.filter(function(p){return !isActiveRecurring(p)})}function activeRecurringCount(){return cloverPlans().length?activePlanCustomers():activeRecurring().length}function weeklyActiveTotal(){return cloverPlans().length?activePlanWeekly():activeRecurring().reduce(function(s,p){return s+Number(p.amount||0)},0)}function weeklyAllScheduled(){return cloverPlans().length?activePlanWeekly()+attentionRecurring().reduce(function(s,p){return s+Number(p.amount||0)},0):db.recurringPayments.reduce(function(s,p){return s+Number(p.amount||0)},0)}
