function applicationCommandPanel(apps){var active=['New','Docs needed','Review','Submitted','Applicant'];var count=function(fn){return apps.filter(fn).length};var rows=[['Active review',count(function(a){return active.indexOf(String(a.stage||a.status||'New'))>=0}),'Decide, request docs, approve, or deny.','Applications','Active','warn'],['Approved',count(function(a){return String(a.stage||a.status||'')==='Approved'}),'Send approval then contract/autopay setup.','Applications','Approved','good'],['Contract handoff',count(function(a){var s=String(a.stage||a.status||'');return s==='Contract'||s==='Active contract'}),'Customer file and autopay row created.','Applications','Contract','blue'],['Denied history',count(function(a){return String(a.stage||a.status||'')==='Denied'}),'Saved reason and history, not active work.','Applications','Denied','bad'],['Removed',count(function(a){return String(a.stage||a.status||'')==='Removed'}),'Hidden from pipeline, still retained.','Applications','Removed','blue']];return '<section class="card section application-command"><div class="section-head"><div><h2>Application command</h2><p>Lead intake through approval, denial, contract handoff, and autopay setup.</p></div><button class="btn primary" data-action="new-app">Add application</button></div><div class="application-lanes">'+rows.map(function(r){return '<button class="application-lane" data-view="'+esc(r[3])+'" data-tab="'+esc(r[4])+'"><span>'+esc(r[0])+'</span><strong>'+esc(r[1])+'</strong><small>'+esc(r[2])+'</small><i class="'+esc(r[5])+'"></i></button>'}).join('')+'</div></section>'}
