function namedPaymentMatch(p){return(db.payments||[]).find(function(x){return x!==p&&!weakPaymentCustomerName(x.customer)&&paymentRecordsShareId(x,p)})}
function descriptionCustomerName(p){var text=String(p&& (p.description||p.notes||p.memo)||'');var m=text.match(/WheelsonAuto\s+.*?payment\s+-\s+(.+)$/i);return m&&!weakPaymentCustomerName(m[1])?m[1].trim():''}
function attemptCustomerMatch(p,roster){var date=dateKeyFrom(p&&p.date),amount=Number(p&&p.amount||0),ids=paymentRecordIds(p),matches=[];(roster||recurringRoster()).forEach(function(r){(r.paymentAttempts||[]).forEach(function(a){var sameId=ids.length&&paymentRecordIds(a).some(function(id){return ids.indexOf(id)>=0});var sameDayAmount=date&&dateKeyFrom(a.date)===date&&amount&&Number(a.amount||0)===amount;var result=String(a.result||a.status||'').toLowerCase();if((sameId||sameDayAmount)&&(result.indexOf('paid')>=0||result.indexOf('submitted')>=0||result.indexOf('fail')>=0||result.indexOf('declin')>=0||sameId))matches.push(r)})});var seen={};matches=matches.filter(function(r){var k=normName(r.customer);if(!k||seen[k])return false;seen[k]=true;return true});return matches.length===1?matches[0]:null}
function failedRosterMatch(p,roster){if(!paymentFailed(p))return null;var amount=Number(p&&p.amount||0);var rows=(roster||recurringRoster()).filter(function(r){return amount&&Number(r.amount||0)===amount&&(todayFailureCount(r)>0||moneyAttentionStatus(r))});var seen={};rows=rows.filter(function(r){var k=normName(r.customer);if(!k||seen[k])return false;seen[k]=true;return true});return rows.length===1?rows[0]:null}
function transactionCustomerName(p,roster){var raw=String(p&&p.customer||'').trim();if(!weakPaymentCustomerName(raw))return raw;roster=roster||recurringRoster();var named=namedPaymentMatch(p);if(named&&named.customer)return named.customer;var described=descriptionCustomerName(p);if(described)return described;var extCustomer=String(p&&p.externalCustomerReference||'').trim();if(extCustomer&&!/^[A-Z0-9]{8,}$/.test(extCustomer)&&!weakPaymentCustomerName(extCustomer))return extCustomer;var ids=[p&&p.recurringPaymentId,p&&p.recurringId,p&&p.cloverSubscriptionId,p&&p.subscriptionId].filter(Boolean).map(String);var r=roster.find(function(x){return ids.indexOf(String(x.id||''))>=0||ids.indexOf(String(x.cloverSubscriptionId||''))>=0});if(!r){var cid=String(p&&(p.cloverCustomerId||p.customerId)||'').trim();if(cid)r=roster.find(function(x){return String(x.cloverCustomerId||'')===cid})}if(!r&&p&&p.paymentRequestId){var req=(db.paymentRequests||[]).find(function(x){return x.id===p.paymentRequestId});if(req&&req.customer)return req.customer;if(req&&req.recurringPaymentId)r=roster.find(function(x){return x.id===req.recurringPaymentId})}if(!r&&p&&p.email)r=roster.find(function(x){return normName(x.email)===normName(p.email)});if(!r&&p&&p.phone)r=roster.find(function(x){return String(x.phone||'').replace(/\D/g,'')===String(p.phone||'').replace(/\D/g,'')});if(!r&&p&&p.vehicle)r=roster.find(function(x){return normName(x.vehicle)===normName(p.vehicle)});if(!r)r=attemptCustomerMatch(p,roster);if(!r)r=failedRosterMatch(p,roster);if(!r&&p&&Number(p.amount)){var same=roster.filter(function(x){return Number(x.amount||0)===Number(p.amount||0)});if(same.length===1)r=same[0]}return r&&r.customer?r.customer:(raw||'Unmatched Clover payment')}

